module freq_div(
    input CLK_in,
    input RST,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1
);

reg [2:0] counter_10;
reg [4:0] counter_50;
reg [9:0] counter_1;

always @(posedge CLK_in or negedge RST) begin
    if (!RST) begin
        CLK_50 <= 1'b0;
        CLK_10 <= 1'b0;
        CLK_1 <= 1'b0;
        counter_10 <= 3'b0;
        counter_50 <= 5'b0;
        counter_1 <= 10'b0;
    end
    else begin
        // 50MHz clock
        if (counter_50 == 5'd24) begin
            CLK_50 <= ~CLK_50;
            counter_50 <= 5'd0;
        end
        else begin
            counter_50 <= counter_50 + 5'd1;
        end

        // 10MHz clock
        if (counter_10 == 3'd4) begin
            CLK_10 <= ~CLK_10;
            counter_10 <= 3'd0;
        end
        else begin
            counter_10 <= counter_10 + 3'd1;
        end

        // 1MHz clock
        if (counter_1 == 10'd99) begin
            CLK_1 <= ~CLK_1;
            counter_1 <= 10'd0;
        end
        else begin
            counter_1 <= counter_1 + 10'd1;
        end
    end
end

endmodule
